import{_ as a,o as t,c as r,ae as i}from"./chunks/framework.oH6zmTcc.js";const s="/atw-rpg/docs/screenshots/mechanic-match-interference.png",n="/atw-rpg/docs/screenshots/mechanic-cards.png",o="/atw-rpg/docs/screenshots/mechanic-decks.png",c="/atw-rpg/docs/screenshots/mechanic-faction-synergy.png",h="/atw-rpg/docs/screenshots/mechanic-wear-and-tear.png",d="/atw-rpg/docs/screenshots/mechanic-expansion-packs.png",l="/atw-rpg/docs/screenshots/mechanic-ringside-actions.png",y=JSON.parse('{"title":"Game Mechanics","description":"","frontmatter":{},"headers":[],"relativePath":"guide/game-mechanics.md","filePath":"guide/game-mechanics.md"}'),m={name:"guide/game-mechanics.md"};function g(p,e,u,f,b,k){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="game-mechanics" tabindex="-1">Game Mechanics <a class="header-anchor" href="#game-mechanics" aria-label="Permalink to &quot;Game Mechanics&quot;">​</a></h1><p>Welcome to the Game Mechanics guide. This documentation is automatically generated from the latest game features.</p><h2 id="cards-walkthrough" tabindex="-1">Cards Walkthrough <a class="header-anchor" href="#cards-walkthrough" aria-label="Permalink to &quot;Cards Walkthrough&quot;">​</a></h2><p>Card detail view: health cost, stamina cost, damage type, and move category.</p><hr><h2 id="match-interference" tabindex="-1">Match Interference <a class="header-anchor" href="#match-interference" aria-label="Permalink to &quot;Match Interference&quot;">​</a></h2><p>Managers and faction members can swing the match in your favor. Perform ringside actions like distracting the referee or sliding in a weapon, but be careful - too much interference will lead to ejections or disqualification!</p><p><img src="'+s+'" alt="Match Interference"></p><hr><h2 id="cards" tabindex="-1">Cards <a class="header-anchor" href="#cards" aria-label="Permalink to &quot;Cards&quot;">​</a></h2><p>The heart of the ATW RPG battle system. Each card represents a move (Strike, Grapple, Aerial, Throw) with specific health and stamina costs and damage effects.</p><p><img src="'+n+'" alt="Cards"></p><hr><h2 id="decks" tabindex="-1">Decks <a class="header-anchor" href="#decks" aria-label="Permalink to &quot;Decks&quot;">​</a></h2><p>Manage wrestler-specific decks. Strategy involves balancing high-damage finishers with efficient setup moves and stamina-recovering taunts.</p><p><img src="'+o+'" alt="Decks"></p><hr><h2 id="faction-synergy" tabindex="-1">Faction Synergy <a class="header-anchor" href="#faction-synergy" aria-label="Permalink to &quot;Faction Synergy&quot;">​</a></h2><p>Factions grow stronger as members work together. Affinity builds through shared matches and victories, unlocking powerful synergy buffs like stamina recovery, finisher damage, and resilience bonuses. High-affinity factions have a mechanical advantage in match outcomes.</p><p><img src="'+c+'" alt="Faction Synergy"></p><hr><h2 id="persistent-wear-tear" tabindex="-1">Persistent Wear &amp; Tear <a class="header-anchor" href="#persistent-wear-tear" aria-label="Permalink to &quot;Persistent Wear &amp; Tear&quot;">​</a></h2><p>Matches take a toll on a wrestler&#39;s body. Physical condition degrades over time based on match intensity (Extreme matches double the wear) and positioning (Main Events are more demanding). Low condition results in health penalties and potential forced retirement.</p><p><img src="'+h+'" alt="Persistent Wear &amp; Tear"></p><hr><h2 id="expansion-packs" tabindex="-1">Expansion Packs <a class="header-anchor" href="#expansion-packs" aria-label="Permalink to &quot;Expansion Packs&quot;">​</a></h2><p>The roster is modular. Content is grouped into Expansion Packs that can be enabled or disabled by administrators. This dynamic system automatically filters wrestlers, teams, and factions based on active sets, allowing for themed seasons and customized gameplay experiences.</p><p><img src="'+d+'" alt="Expansion Packs"></p><hr><h2 id="ringside-actions" tabindex="-1">Ringside Actions <a class="header-anchor" href="#ringside-actions" aria-label="Permalink to &quot;Ringside Actions&quot;">​</a></h2><p>Managers and faction members can swing the match in your favor. Perform ringside actions like coaching, distracting the referee, or sliding in a weapon, but be careful - too much illegal interference will lead to ejections or disqualification!</p><p><img src="'+l+'" alt="Ringside Actions"></p><hr><h2 id="video-walkthroughs" tabindex="-1">Video Walkthroughs <a class="header-anchor" href="#video-walkthroughs" aria-label="Permalink to &quot;Video Walkthroughs&quot;">​</a></h2><h3 id="managing-cards" tabindex="-1">Managing Cards <a class="header-anchor" href="#managing-cards" aria-label="Permalink to &quot;Managing Cards&quot;">​</a></h3><p>Card name updated in place — changes persist immediately with no page reload, keeping the editing flow smooth during show preparation. Updated cards are reflected in all decks that reference them automatically.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/card-list-manage.mp4" type="video/mp4"></video><hr><h3 id="creating-a-card" tabindex="-1">Creating a Card <a class="header-anchor" href="#creating-a-card" aria-label="Permalink to &quot;Creating a Card&quot;">​</a></h3><p>New card created — it appears in the grid immediately and is ready to be assigned stats, a card set, and rules for use in segments. Open the Edit dialog to configure health cost, stamina cost, and damage values.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/create-card.mp4" type="video/mp4"></video><hr><h3 id="decks-walkthrough" tabindex="-1">Decks Walkthrough <a class="header-anchor" href="#decks-walkthrough" aria-label="Permalink to &quot;Decks Walkthrough&quot;">​</a></h3><p>These move sets are what the AI draws from during match narration — a richer deck with varied move types leads to more dynamic and realistic commentary.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/mechanic-decks-walkthrough.mp4" type="video/mp4"></video><hr><h3 id="cards-walkthrough-1" tabindex="-1">Cards Walkthrough <a class="header-anchor" href="#cards-walkthrough-1" aria-label="Permalink to &quot;Cards Walkthrough&quot;">​</a></h3><p>Card detail view shows health cost, stamina cost, damage type, and move category. These values are referenced directly by the match engine and AI narration when describing what happened in a segment.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/mechanic-cards-walkthrough.mp4" type="video/mp4"></video><hr>',50)])])}const v=a(m,[["render",g]]);export{y as __pageData,v as default};
